let prior = [];
try {
  const raw = $('Leer Historial').first().json.messages;
  prior = Array.isArray(raw) ? raw : (raw ? JSON.parse(raw) : []);
} catch (e) { prior = []; }

// ── RESET POR INACTIVIDAD ──────────────────────────────────
// Si el último mensaje fue hace más de 1 hora, el cliente
// empezó una nueva conversación. Ignoramos el historial anterior.
let gapMessage = '';
const histUpdatedAt = $('Leer Historial').first().json.updated_at;
if (histUpdatedAt) {
  const minsSince = (Date.now() - new Date(histUpdatedAt).getTime()) / 60000;
  if (minsSince > 60) {
    prior = [];
  } else if (minsSince > 10) {
    gapMessage = '\nNOTA: Pasaron más de ' + Math.round(minsSince) + ' minutos desde el último mensaje del cliente. Si el cliente NO retoma el tema anterior, pregúntale si continuamos con lo que hablábamos o si prefiere empezar de nuevo.';
  }
}
// ───────────────────────────────────────────────────────────
// ── RETOMAR POR INACTIVIDAD BOT ────────────────────────────
// Si el Inactividad Bot marcó la conversación como 'avisado'
// (envió "¿Sigues ahí?"), el cliente está retomando.
// Continuamos naturalmente sin saludo.
const inactividadEstado = $('Leer Historial').first().json.inactividad_estado;
if (inactividadEstado === 'avisado') {
  gapMessage = '\nNOTA: El cliente retoma la conversación después de que le preguntamos si seguía ahí. Continúa naturalmente donde íbamos. Si parece no recordar, haz un resumen breve de lo último que hablaban.';
}
// ───────────────────────────────────────────────────────────

const priorEsc = JSON.stringify(prior).replace(/'/g, "''"); // safe para embeber en '...'::jsonb

// ── 0. SHORT-CIRCUIT FUERA DE HORARIO ───────────────────────
// [DECISIÓN DE INGENIERÍA AÑADIDA — NO estaba en el diseño aprobado]
// fueraDeHorario es booleano y determinista. Resolverlo en código evita una
// llamada al LLM y corrige un bug latente: el prompt original referenciaba
